import { NextResponse } from 'next/server'
import { execSync } from 'child_process'
import { readFileSync, writeFileSync } from 'fs'

const JOBS_PATH = '/Users/little_shuai/.openclaw/cron/jobs.json'
const OPENCLAW = '/Users/little_shuai/.nvm/versions/node/v24.13.0/bin/openclaw'
const EXEC_ENV = { ...process.env, PATH: `/Users/little_shuai/.nvm/versions/node/v24.13.0/bin:${process.env.PATH || ''}` }

interface RawJob {
  id: string
  name?: string
  enabled?: boolean
  agentId?: string
  schedule?: { kind?: string; expr?: string; everyMs?: number; at?: string; tz?: string }
  payload?: { kind?: string; message?: string; [k: string]: unknown }
  state?: {
    lastRunAtMs?: number
    lastStatus?: string
    lastError?: string
    lastDurationMs?: number
    consecutiveErrors?: number
    nextRunAtMs?: number
    [k: string]: unknown
  }
  [k: string]: unknown
}

function readJobs() {
  return JSON.parse(readFileSync(JOBS_PATH, 'utf-8'))
}

function describeSchedule(s?: RawJob['schedule']): string {
  if (!s) return '—'
  if (s.kind === 'cron' && s.expr) {
    const expr = s.expr
    if (expr.match(/^\d+,\d+ \* \* \* \*/)) return 'every 30min'
    if (expr.match(/^\*\/15 /)) return 'every 15min'
    const everyH = expr.match(/^\d+ \*\/(\d+) /)
    if (everyH) return `every ${everyH[1]}h`
    const daily = expr.match(/^(\d+) (\d+) \* \* \*/)
    if (daily) return `daily ${daily[2]}:${daily[1].padStart(2, '0')}`
    return `${expr} ${s.tz || ''}`
  }
  if (s.kind === 'every' && s.everyMs) {
    const h = s.everyMs / 3600000
    if (h >= 1) return `every ${h}h`
    return `every ${s.everyMs / 60000}min`
  }
  if (s.kind === 'at' && s.at) return `once: ${s.at}`
  return JSON.stringify(s)
}

function normalizeJob(raw: RawJob) {
  return {
    id: raw.id,
    name: raw.name || raw.id,
    enabled: raw.enabled ?? false,
    agentId: raw.agentId || '',
    schedule: raw.schedule || {},
    scheduleDescription: describeSchedule(raw.schedule),
    lastRun: raw.state?.lastRunAtMs ? new Date(raw.state.lastRunAtMs).toISOString() : undefined,
    lastRunStatus: raw.state?.lastStatus,
    lastRunError: raw.state?.lastError,
    consecutiveErrors: raw.state?.consecutiveErrors || 0,
    nextRun: raw.state?.nextRunAtMs ? new Date(raw.state.nextRunAtMs).toISOString() : undefined,
    payload: raw.payload || {},
  }
}

function runCli(cmd: string): string {
  try {
    return execSync(cmd, { encoding: 'utf-8', timeout: 15000, env: EXEC_ENV })
  } catch (err: any) {
    // openclaw CLI exits 1 for "already-running" etc but stdout has valid data
    return err.stdout || err.stderr || ''
  }
}

export async function GET() {
  try {
    const data = readJobs()
    const rawJobs: RawJob[] = data.jobs ?? []
    const osJobs = rawJobs.filter(j => {
      const name = (j.name || '').toLowerCase()
      return name.includes('os-workshop') || name.includes('openclaw-pr')
    })
    return NextResponse.json(osJobs.map(normalizeJob))
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : String(err)
    return NextResponse.json({ error: msg }, { status: 500 })
  }
}

export async function POST(req: Request) {
  try {
    const body = await req.json()
    const { action, jobId, patch } = body

    if (!action || !jobId) {
      return NextResponse.json({ error: 'action and jobId required' }, { status: 400 })
    }

    switch (action) {
      case 'run': {
        const output = runCli(`${OPENCLAW} cron run ${jobId}`)
        const trimmed = output.trim()
        try {
          return NextResponse.json({ ok: true, ...JSON.parse(trimmed) })
        } catch {
          return NextResponse.json({ ok: true, output: trimmed })
        }
      }

      case 'enable':
      case 'disable': {
        const data = readJobs()
        const job = (data.jobs ?? []).find((j: any) => j.id === jobId)
        if (!job) return NextResponse.json({ error: 'job not found' }, { status: 404 })
        job.enabled = action === 'enable'
        writeFileSync(JOBS_PATH, JSON.stringify(data, null, 2), 'utf-8')
        return NextResponse.json({ ok: true })
      }

      case 'edit': {
        // Schedule: direct file I/O (only cron expressions)
        // Message: direct file I/O
        const data = readJobs()
        const job = (data.jobs ?? []).find((j: any) => j.id === jobId)
        if (!job) return NextResponse.json({ error: 'job not found' }, { status: 404 })

        let changed = false
        if (patch?.payload?.message) {
          job.payload.message = patch.payload.message
          changed = true
        }
        if (patch?.schedule) {
          const sched = String(patch.schedule).trim()
          if (sched.length > 0) {
            job.schedule = { ...job.schedule, kind: 'cron', expr: sched, tz: job.schedule?.tz || 'America/Los_Angeles' }
            changed = true
          }
        }
        if (changed) {
          writeFileSync(JOBS_PATH, JSON.stringify(data, null, 2), 'utf-8')
        }
        return NextResponse.json({ ok: true })
      }

      default:
        return NextResponse.json({ error: `unknown action: ${action}` }, { status: 400 })
    }
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : String(err)
    return NextResponse.json({ error: msg }, { status: 500 })
  }
}
